arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing documents and raw SQL queries (c.Discriminator) still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id format from "Product|123" to "123".
        // Preserve the old compound format so existing documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed HasIndex — EF Core 9 Cosmos provider throws at startup for HasIndex calls.
    // Manage Cosmos DB indexing policies via the Azure Portal, Bicep, or Terraform.
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator" via HasDiscriminator().
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider removed sync I/O — use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

